fun solve(points: Array<Array<Long>>): Long {
    val n = points.size
    var count = 0L

    fun gcdPositive(a: Long, b: Long): Long {
        if (b == 0L) return a
        return gcdPositive(b, a % b)
    }

    fun toSlope(p: Array<Long>, q: Array<Long>): Pair<Long, Long> {
        val dx = q[0] - p[0]
        val dy = q[1] - p[1]
        if (dx == 0L) {
            return Pair(0, 1)
        }
        var dx0 = dx
        var dy0 = dy
        if (dx0 < 0) {
            dx0 = -dx0
            dy0 = -dy0
        }
        val ady = if (dy0 >= 0) dy0 else -dy0
        val g = gcdPositive(dx0, ady)
        val sx = dx0 / g
        val sy = dy0 / g
        return Pair(sx, sy)
    }

    fun getConvexHull(points: List<Array<Long>>): List<Array<Long>> {
        if (points.size <= 1) return points
        val sorted = points.sortedWith(compareBy({ it[0] }, { it[1] }))
        val lower = mutableListOf<Array<Long>>()
        for (i in sorted.indices) {
            while (lower.size >= 2) {
                val o = lower[lower.size - 2]
                val a = lower.last()
                val b = sorted[i]
                val cross = (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0])
                if (cross <= 0) {
                    lower.removeAt(lower.size - 1)
                } else {
                    break
                }
            }
            lower.add(sorted[i])
        }
        val upper = mutableListOf<Array<Long>>()
        for (i in sorted.indices.reversed()) {
            while (upper.size >= 2) {
                val o = upper[upper.size - 2]
                val a = upper.last()
                val b = sorted[i]
                val cross = (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0])
                if (cross <= 0) {
                    upper.removeAt(upper.size - 1)
                } else {
                    break
                }
            }
            upper.add(sorted[i])
        }
        lower.removeAt(lower.size - 1)
        upper.removeAt(upper.size - 1)
        return lower + upper
    }

    for (i in 0 until n) {
        for (j in i + 1 until n) {
            for (k in j + 1 until n) {
                for (l in k + 1 until n) {
                    val p = listOf(points[i], points[j], points[k], points[l])
                    val hull = getConvexHull(p)
                    if (hull.size != 4) {
                        continue
                    }
                    val slope0 = toSlope(hull[0], hull[1])
                    val slope1 = toSlope(hull[1], hull[2])
                    val slope2 = toSlope(hull[2], hull[3])
                    val slope3 = toSlope(hull[3], hull[0])
                    if (slope0 == slope2 || slope1 == slope3) {
                        count++
                    }
                }
            }
        }
    }
    return count
}
```

