fun gcd(a: Long, b: Long): Long {
    var x = kotlin.math.abs(a)
    var y = kotlin.math.abs(b)
    while (x != 0L) {
        val temp = x
        x = y % x
        y = temp
    }
    return y
}

fun normalizeSlope(dx: Long, dy: Long): Pair<Long, Long> {
    if (dx == 0L && dy == 0L) {
        return 0L to 0L
    }
    if (dx == 0L) {
        return 0L to 1L
    }
    if (dy == 0L) {
        return 1L to 0L
    }
    val g = gcd(dx, dy)
    var ndx = dx / g
    var ndy = dy / g
    if (ndx < 0) {
        ndx = -ndx
        ndy = -ndy
    } else if (ndx == 0L && ndy < 0) {
        ndy = -ndy
    }
    return ndx to ndy
}

fun solve(points: Array<Array<Long>>): Long {
    val n = points.size
    val slopeMap = mutableMapOf<Pair<Long, Long>, MutableList<Int>>()

    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val dx = points[j][0] - points[i][0]
            val dy = points[j][1] - points[i][1]
            val slope = normalizeSlope(dx, dy)
            if (slope == (0L to 0L)) continue
            val list = slopeMap.getOrPut(slope) { mutableListOf() }
            list.add(i)
            list.add(j)
        }
    }

    var A = 0L
    for ((_, list) in slopeMap) {
        val m = list.size / 2
        if (m < 2) continue
        val total_pairs = m.toLong() * (m - 1) / 2
        val freq = mutableMapOf<Int, Int>()
        for (vertex in list) {
            freq[vertex] = freq.getOrDefault(vertex, 0) + 1
        }
        var nonDisjoint = 0L
        for (count in freq.values) {
            nonDisjoint += count.toLong() * (count - 1) / 2
        }
        A += (total_pairs - nonDisjoint)
    }

    val midPointMap = mutableMapOf<Pair<Long, Long>, Int>()
    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val midX = points[i][0] + points[j][0]
            val midY = points[i][1] + points[j][1]
            val key = midX to midY
            midPointMap[key] = midPointMap.getOrDefault(key, 0) + 1
        }
    }
    var B = 0L
    for (count in midPointMap.values) {
        if (count < 2) continue
        B += count.toLong() * (count - 1) / 2
    }

    return A - B
}
