fun solve(points: Array<Array<Long>>): Long {
    val n = points.size
    val midMap = mutableMapOf<Pair<Long, Long>, Long>()
    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val key = points[i][0] + points[j][0] to points[i][1] + points[j][1]
            midMap[key] = midMap.getOrDefault(key, 0) + 1
        }
    }
    var parallelogramCount = 0L
    for (count in midMap.values) {
        if (count >= 2) {
            parallelogramCount += count * (count - 1) / 2
        }
    }

    val linesBySlope = mutableMapOf<Pair<Long, Long>, MutableMap<Long, MutableSet<Int>>>()

    fun gcd(a: Long, b: Long): Long {
        var x = kotlin.math.abs(a)
        var y = kotlin.math.abs(b)
        while (y != 0L) {
            val temp = x % y
            x = y
            y = temp
        }
        return x
    }

    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val dx = points[j][0] - points[i][0]
            val dy = points[j][1] - points[i][1]
            if (dx == 0L && dy == 0L) continue

            val g = gcd(dx, dy)
            var ndx = if (g != 0L) dx / g else dx
            var ndy = if (g != 0L) dy / g else dy
            if (ndx < 0) {
                ndx = -ndx
                ndy = -ndy
            } else if (ndx == 0L && ndy < 0) {
                ndy = -ndy
            }

            val xi = points[i][0]
            val yi = points[i][1]
            val c = ndy * xi - ndx * yi

            val slopeKey = ndx to ndy
            val innerMap = linesBySlope.getOrPut(slopeKey) { mutableMapOf() }
            val pointSet = innerMap.getOrPut(c) { mutableSetOf() }
            pointSet.add(i)
            pointSet.add(j)
        }
    }

    var totalTrapezoids = 0L
    for ((_, innerMap) in linesBySlope) {
        val sizes = innerMap.values.map { it.size.toLong() }
        val comb2 = sizes.map { if (it < 2) 0L else it * (it - 1) / 2 }
        val m = comb2.size
        if (m < 2) continue

        var sumComb2 = 0L
        var sumSq = 0L
        for (c in comb2) {
            sumComb2 += c
            sumSq += c * c
        }
        val totalInSlope = (sumComb2 * sumComb2 - sumSq) / 2
        totalTrapezoids += totalInSlope
    }

    return totalTrapezoids - parallelogramCount
}
